672:             my_descr = PyArray_DESCR(a);
673:         }
674:         out = (PyArrayObject *)PyArray_Empty(PyArray_NDIM(a), PyArray_DIMS(a),
675:                                              my_descr,
676:                                              PyArray_ISFORTRAN(a));
677:         if (out == NULL) {
678:             return NULL;
679:         }
680:     }
681:     else {
682:         Py_INCREF(out);
683:     }
684:     f = PyFloat_FromDouble(power_of_ten(decimals));
685:     if (f == NULL) {
686:         return NULL;
687:     }
688:     ret = PyObject_CallFunction(op1, "OOO", a, f, out);
689:     if (ret == NULL) {
690:         goto finish;
691:     }
692:     tmp = PyObject_CallFunction(n_ops.rint, "OO", ret, ret);
693:     if (tmp == NULL) {
694:         Py_DECREF(ret);
695:         ret = NULL;
696:         goto finish;
697:     }
698:     Py_DECREF(tmp);
699:     tmp = PyObject_CallFunction(op2, "OOO", ret, f, ret);
700:     if (tmp == NULL) {
701:         Py_DECREF(ret);
702:         ret = NULL;
703:         goto finish;
704:     }
705:     Py_DECREF(tmp);
706: 
707:  finish:
708:     Py_DECREF(f);
709:     Py_DECREF(out);
710:     if (ret_int && ret != NULL) {
711:         Py_INCREF(PyArray_DESCR(a));
712:         tmp = PyArray_CastToType((PyArrayObject *)ret,
713:                                  PyArray_DESCR(a), PyArray_ISFORTRAN(a));
714:         Py_DECREF(ret);
715:         return tmp;
716:     }
717:     return ret;
