286: static PyObject *
287: array_inplace_matrix_multiply(PyArrayObject *self, PyObject *other)
288: {
289:     INPLACE_GIVE_UP_IF_NEEDED(self, other,
290:             nb_inplace_matrix_multiply, array_inplace_matrix_multiply);
291: 
292:     PyObject *args = PyTuple_Pack(3, self, other, self);
293:     if (args == NULL) {
294:         return NULL;
295:     }
296:     PyObject *kwargs;
297: 
298:     /*
299:      * Unlike `matmul(a, b, out=a)` we ensure that the result is not broadcast
300:      * if the result without `out` would have less dimensions than `a`.
301:      * Since the signature of matmul is '(n?,k),(k,m?)->(n?,m?)' this is the
302:      * case exactly when the second operand has both core dimensions.
303:      *
304:      * The error here will be confusing, but for now, we enforce this by
305:      * passing the correct `axes=`.
306:      */
307:     if (PyArray_NDIM(self) == 1) {
308:         kwargs = npy_static_pydata.axes_1d_obj_kwargs;
309:     }
310:     else {
311:         kwargs = npy_static_pydata.axes_2d_obj_kwargs;
312:     }
313:     PyObject *res = PyObject_Call(n_ops.matmul, args, kwargs);
314:     Py_DECREF(args);
315: 
316:     if (res == NULL) {
317:         /*
318:          * AxisError should indicate that the axes argument didn't work out
319:          * which should mean the second operand not being 2 dimensional.
320:          */
321:         if (PyErr_ExceptionMatches(npy_static_pydata.AxisError)) {
322:             PyErr_SetString(PyExc_ValueError,
323:                 "inplace matrix multiplication requires the first operand to "
324:                 "have at least one and the second at least two dimensions.");
325:         }
326:     }
327: 
328:     return res;
329: }
