331: static int
332: fast_scalar_power(PyObject *o1, PyObject *o2, int inplace, PyObject **result)
333: {
334:     PyObject *fastop = NULL;
335: 
336:     if (PyLong_CheckExact(o2)) {
337:         int overflow = 0;
338:         long exp = PyLong_AsLongAndOverflow(o2, &overflow);
339:         if (overflow != 0) {
340:             return -1;
341:         }
342: 
343:         if (exp == -1) {
344:             fastop = n_ops.reciprocal;
345:         }
346:         else if (exp == 2) {
347:             fastop = n_ops.square;
348:         }
349:         else {
350:             return 1;
351:         }
352:     }
353:     else if (PyFloat_CheckExact(o2)) {
354:         double exp = PyFloat_AsDouble(o2);
355:         if (exp == 0.5) {
356:             fastop = n_ops.sqrt;
357:         }
358:         else {
359:             return 1;
360:         }
361:     }
362:     else {
363:         return 1;
364:     }
365: 
366:     PyArrayObject *a1 = (PyArrayObject *)o1;
367:     if (PyArray_ISOBJECT(a1)) {
368:         return 1;
369:     }
370:     if (fastop != n_ops.square && !PyArray_ISFLOAT(a1) && !PyArray_ISCOMPLEX(a1)) {
371:         // we special-case squaring for any array type
