633: static int
634: _array_nonzero(PyArrayObject *mp)
635: {
636:     npy_intp n;
637: 
638:     n = PyArray_SIZE(mp);
639:     if (n == 1) {
640:         int res;
641:         if (Py_EnterRecursiveCall(" while converting array to bool")) {
642:             return -1;
643:         }
644:         res = PyDataType_GetArrFuncs(PyArray_DESCR(mp))->nonzero(PyArray_DATA(mp), mp);
645:         /* nonzero has no way to indicate an error, but one can occur */
646:         if (PyErr_Occurred()) {
647:             res = -1;
648:         }
649:         Py_LeaveRecursiveCall();
650:         return res;
651:     }
652:     else if (n == 0) {
653:         PyErr_SetString(PyExc_ValueError,
654:                 "The truth value of an empty array is ambiguous. "
655:                 "Use `array.size > 0` to check that an array is not empty.");
656:         return -1;
657:     }
658:     else {
659:         PyErr_SetString(PyExc_ValueError,
660:                         "The truth value of an array "
661:                         "with more than one element is ambiguous. "
662:                         "Use a.any() or a.all()");
663:         return -1;
664:     }
665: }
