667: /*
668:  * Convert the array to a scalar if allowed, and apply the builtin function
669:  * to it. The where argument is passed onto Py_EnterRecursiveCall when the
670:  * array contains python objects.
671:  */
672: NPY_NO_EXPORT PyObject *
673: array_scalar_forward(PyArrayObject *v,
674:                      PyObject *(*builtin_func)(PyObject *),
675:                      const char *where)
676: {
677:     if (check_is_convertible_to_scalar(v) < 0) {
678:         return NULL;
679:     }
680: 
681:     PyObject *scalar;
682:     scalar = PyArray_GETITEM(v, PyArray_DATA(v));
683:     if (scalar == NULL) {
684:         return NULL;
685:     }
686: 
687:     /* Need to guard against recursion if our array holds references */
688:     if (PyDataType_REFCHK(PyArray_DESCR(v))) {
689:         PyObject *res;
690:         if (Py_EnterRecursiveCall(where) != 0) {
691:             Py_DECREF(scalar);
692:             return NULL;
693:         }
694:         res = builtin_func(scalar);
695:         Py_DECREF(scalar);
696:         Py_LeaveRecursiveCall();
697:         return res;
698:     }
699:     else {
700:         PyObject *res;
701:         res = builtin_func(scalar);
702:         Py_DECREF(scalar);
703:         return res;
704:     }
705: }
